// Parse which endpoint was requested via query param
// e.g. /dashboard?endpoint=kpis&period=7d
const query = $input.first().json.query || {};
const endpoint = query.endpoint || 'kpis';
const period = query.period || '7d';

const periodDays = { '7d': 7, '30d': 30, '90d': 90 }[period] || 7;

return { endpoint, period, periodDays };

// Format KPI response
const row = $input.first().json;
const trend = row.daily_trend || [];

const totalPlatformViews = (row.instagram_views||0) + (row.tiktok_views||0) + (row.youtube_views||0);

return {
  success: true,
  endpoint: 'kpis',
  data: {
    total_views: parseInt(row.total_views) || 0,
    viral_count: parseInt(row.viral_count) || 0,
    avg_engagement: parseFloat(row.avg_engagement) || 0,
    active_accounts: parseInt(row.active_accounts) || 0,
    underperforming: parseInt(row.underperforming) || 0,
    platform_split: {
      instagram: totalPlatformViews > 0 ? Math.round((row.instagram_views||0) / totalPlatformViews * 100) : 0,
      tiktok: totalPlatformViews > 0 ? Math.round((row.tiktok_views||0) / totalPlatformViews * 100) : 0,
      youtube: totalPlatformViews > 0 ? Math.round((row.youtube_views||0) / totalPlatformViews * 100) : 0
    },
    daily_trend: trend
  },
  cached_at: new Date().toISOString()
};

// Format accounts response
const items = $input.all();

const accounts = items.map(item => {
  const a = item.json;
  return {
    account_id: a.account_id,
    username: a.username,
    platform: a.platform,
    niche: a.niche,
    followers: parseInt(a.followers_count) || 0,
    views: parseInt(a.views_period) || 0,
    engagement: parseFloat(a.engagement_rate) || 0,
    viral_reels: parseInt(a.viral_reels) || 0,
    posts: parseInt(a.posts_count) || 0,
    status: a.status || 'low',
    trend: (a.trend || []).map(t => parseInt(t.views) || 0)
  };
});

return {
  success: true,
  endpoint: 'accounts',
  count: accounts.length,
  data: accounts,
  cached_at: new Date().toISOString()
};

// Format viral reels response
const items = $input.all();

const reels = items.map(item => {
  const r = item.json;
  return {
    content_id: r.content_id,
    hook: r.hook || 'Untitled',
    platform: r.platform,
    account: r.account_name,
    niche: r.niche,
    url: r.url,
    posted_at: r.posted_at,

    // Performance
    views: parseInt(r.views) || 0,
    likes: parseInt(r.likes) || 0,
    comments: parseInt(r.comments) || 0,
    shares: parseInt(r.shares) || 0,
    saves: parseInt(r.saves) || 0,

    // Full genome for traceability
    genome: {
      script: r.script_text || null,
      script_id: r.script_id || null,
      idea: r.idea_text || null,
      idea_id: r.idea_id || null,
      hook_text: r.hook_text || null,
      hook_pattern: r.hook_pattern || null,
      transcript: r.transcript_text ? r.transcript_text.substring(0, 300) : null,
      source_reel_url: r.source_reel_url || null,
      source_views: parseInt(r.source_views) || 0,
      source_creator: r.source_creator || null,
      source_niche: r.source_niche || null
    }
  };
});

return {
  success: true,
  endpoint: 'viral',
  count: reels.length,
  data: reels,
  cached_at: new Date().toISOString()
};

// Format hooks + pipeline response
const items = $input.all();

// First result set is hooks, remaining are pipeline counts
const hooks = items
  .filter(i => i.json.pattern_name)
  .map(item => {
    const h = item.json;
    const maxEng = 10;
    return {
      pattern: h.pattern_name,
      uses: parseInt(h.uses) || 0,
      avg_views: parseInt(h.avg_views) || 0,
      avg_engagement: parseFloat(h.avg_engagement) || 0,
      best_views: parseInt(h.best_views) || 0,
      best_hook: h.best_hook_text || '',
      fill_pct: Math.min(Math.round((parseFloat(h.avg_engagement) / maxEng) * 100), 100)
    };
  });

const ideaRow = items.find(i => i.json.ideas_pending !== undefined)?.json || {};
const scriptRow = items.find(i => i.json.scripts_ready !== undefined)?.json || {};
const videoRow = items.find(i => i.json.videos_rendering !== undefined)?.json || {};

return {
  success: true,
  endpoint: 'hooks',
  data: {
    patterns: hooks,
    pipeline: {
      ideas_pending: parseInt(ideaRow.ideas_pending) || 0,
      ideas_approved: parseInt(ideaRow.ideas_approved) || 0,
      scripts_ready: parseInt(scriptRow.scripts_ready) || 0,
      scripts_draft: parseInt(scriptRow.scripts_draft) || 0,
      videos_rendering: parseInt(videoRow.videos_rendering) || 0,
      videos_done: parseInt(videoRow.videos_done) || 0
    }
  },
  cached_at: new Date().toISOString()
};
